import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Calendar, User, AlignLeft, BarChart } from 'lucide-react';
import axios from 'axios';

const AddTaskModal = ({ isOpen, onClose, refreshTasks }) => {
  const [members, setMembers] = useState([]);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    priority: 'Normal',
    dueDate: '',
    assignedTo: ''
  });

  // Fetch all members for assignment dropdown
  useEffect(() => {
    const fetchUsers = async () => {
      try {
        const token = localStorage.getItem('token');
        const res = await axios.get('http://localhost:5000/api/auth/users', {
          headers: { 'x-auth-token': token }
        });
        // Sirf 'member' role walo ko filter karke dropdown mein dikhana
        setMembers(res.data.filter(user => user.role === 'member'));
      } catch (err) {
        console.error("Error fetching users", err);
      }
    };

    if (isOpen) fetchUsers();
  }, [isOpen]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      await axios.post('http://localhost:5000/api/tasks', formData, {
        headers: { 'x-auth-token': token }
      });
      refreshTasks();
      onClose();
      // Reset form
      setFormData({ title: '', description: '', priority: 'Normal', dueDate: '', assignedTo: '' });
    } catch (err) {
      alert("Failed to create task. Check all fields.");
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
          <motion.div 
            initial={{ opacity: 0, scale: 0.9, y: 30 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 30 }}
            className="w-full max-w-xl bg-[#1e293b] border border-white/10 p-8 rounded-[2.5rem] shadow-2xl relative"
          >
            <button onClick={onClose} className="absolute top-6 right-6 text-gray-400 hover:text-white transition-all">
              <X size={24} />
            </button>

            <h2 className="text-3xl font-black text-white mb-2 italic">CREATE TASK</h2>
            <p className="text-gray-400 text-sm mb-8">Assign new responsibilities to your team members.</p>

            <form onSubmit={handleSubmit} className="space-y-5">
              {/* Task Title */}
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Task Title"
                  className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:outline-none focus:border-indigo-500 transition-all"
                  value={formData.title}
                  onChange={(e) => setFormData({...formData, title: e.target.value})}
                  required
                />
              </div>

              {/* Description */}
              <textarea 
                placeholder="Detailed Description..."
                className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl text-white h-28 focus:outline-none focus:border-indigo-500 transition-all resize-none"
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
                required
              />

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Priority */}
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest text-gray-500 font-bold ml-1">Priority</label>
                  <select 
                    className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:outline-none appearance-none cursor-pointer"
                    value={formData.priority}
                    onChange={(e) => setFormData({...formData, priority: e.target.value})}
                  >
                    <option value="Low">Low</option>
                    <option value="Normal">Normal</option>
                    <option value="High">High</option>
                  </select>
                </div>

                {/* Due Date */}
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest text-gray-500 font-bold ml-1">Deadline</label>
                  <input 
                    type="date" 
                    className="w-full p-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:outline-none focus:border-indigo-500 transition-all"
                    value={formData.dueDate}
                    onChange={(e) => setFormData({...formData, dueDate: e.target.value})}
                    required
                  />
                </div>
              </div>

              {/* Assignment Dropdown */}
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest text-gray-500 font-bold ml-1">Assign To Team Member</label>
                <select 
                  className="w-full p-4 bg-[#0f172a] border border-white/10 rounded-2xl text-white focus:outline-none cursor-pointer"
                  value={formData.assignedTo}
                  onChange={(e) => setFormData({...formData, assignedTo: e.target.value})}
                  required
                >
                  <option value="">Select a member...</option>
                  {members.map(member => (
                    <option key={member._id} value={member._id}>
                      {member.name} ({member.email})
                    </option>
                  ))}
                </select>
              </div>

              <button 
                type="submit" 
                className="w-full py-5 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-black text-lg hover:shadow-[0_0_30px_rgba(79,70,229,0.4)] hover:scale-[1.02] transition-all mt-4"
              >
                DEPLOY TASK
              </button>
            </form>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default AddTaskModal;
